#include <stdio.h>
#include <stdint.h>

// Function demonstrating bitwise operations
uint8_t manipulate_bits(uint8_t value, uint8_t mask) {
    // Left shift: move bits left by 2 positions (multiply by 4)
    uint8_t shifted_left = value << 2;

    // Right shift: move bits right by 1 position (divide by 2)
    uint8_t shifted_right = value >> 1;

    // Bitwise OR: set bits that are 1 in either operand
    uint8_t or_result = value | mask;

    // Bitwise AND: keep only bits that are 1 in both operands
    uint8_t and_result = value & mask;

    // Combine operations to demonstrate practical usage
    // Example: extract specific bits, then manipulate them
    uint8_t extracted = (value & 0x0F) << 2;  // Extract lower 4 bits, shift left by 2
    uint8_t combined = extracted | (mask & 0xF0);  // Combine with upper 4 bits of mask

    printf("Original value: %02X\n", value);
    printf("Mask:           %02X\n", mask);
    printf("Shifted left:   %02X\n", shifted_left);
    printf("Shifted right:  %02X\n", shifted_right);
    printf("OR result:      %02X\n", or_result);
    printf("AND result:     %02X\n", and_result);
    printf("Extracted & combined: %02X\n", combined);

    return combined;
}

int main() {
    uint8_t test_value = 0b11010110;  // 0xD6
    uint8_t test_mask = 0b10101010;   // 0xAA

    printf("=== Bitwise Operations Demo ===\n");
    manipulate_bits(test_value, test_mask);

    return 0;
}
